dt-example.js:
new DataTable('#example', {
	layout: {
		top1: {
			searchBuilder: {
				conditions: {
					num: {
						// Overwrite the equals condition for the num type
						'+-5': {
							// This function decides whether to include the
							// criteria in the search. `els` is an array of
							// `Dom` instances.
							isInputValid: function (els, that) {
								return els[0].val() !== '';
							},

							// This is the string displayed in the condition
							// select
							conditionName: '+- 5',

							// This function gathers/sets the values from the
							// dom elements created in the init function that
							// are to be used for searching
							inputValue: function (els) {
								return [els[0].val()];
							},

							// This function initialises the criteria,
							// specifically any dom elements that are required
							// for its use
							init: function (that, fn, preDefined = null) {
								// Declare the input element
								let el = DataTable.Dom.c('input')
									.classAdd(that.classes.value)
									.classAdd(that.classes.input)
									.on('input', function () {
										fn(that, this);
									});

								// If there is a preDefined value then add it
								if (preDefined !== null) {
									el.val(preDefined[0]);
								}

								return el;
							},

							// Straightforward search function comparing value
							// from table and comparison from the input element
							// These values are retrieved in `inputValue`
							search: function (value, comparison) {
								return +value <= +comparison[0] + 5 && +value >= +comparison[0] - 5;
							}
						}
					}
				}
			}
		}
	}
});
